// T102 QRCodeGeneratorHandler — CORRECT platform-only declaration
// Factory dependency MUST declare PLATFORM-ONLY (no tenant override)
// factoryDependencies: [{ factoryId: 'F275', interfaceName: 'IQRService', platformOnly: true }]

async generateQRCode(ticketId: string): Promise<DataProcessResult<QRResult>> {
  // F275 is injected as platform service — tenant cannot override
  const qrResult = await this.qrService.generate({ ticketId, tenantId: this.tenantContext.get() });
  // DNA-8: store QR record BEFORE event
  await this.db.storeDocument('ticket-qr-codes', { ticketId, qrToken: qrResult.data?.token, knowledgeScope: 'PRIVATE' }, ticketId);
  await this.queue.enqueue('ticket.qr.generated', { ticketId });
  return DataProcessResult.success({ ticketId, qrToken: qrResult.data?.token });
}
// WRONG: IExternalServiceFactory.createAsync('qr-service') — allows tenant QR implementation
